import React from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";

export default function NotFound() {
    const navigate = useNavigate();

    return (
        <div style={{
            minHeight: "100vh",
            background: "#fafafa",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif",
            padding: "20px",
            position: "relative",
        }}>
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6 }}
                style={{
                    maxWidth: 520,
                    width: "100%",
                    position: "relative",
                    zIndex: 1,
                }}
            >
                {/* Main Card */}
                <div style={{
                    background: "#ffffff",
                    borderRadius: "24px",
                    padding: "48px 40px",
                    boxShadow: "0 10px 40px rgba(0,0,0,0.08)",
                    border: "1px solid #f0f0f0",
                    textAlign: "center",
                }}>
                    {/* Logo */}
                    <div style={{ marginBottom: 32 }}>
                        <img
                            src="/assets/images/capavate.png"
                            alt="Capavate"
                            style={{ height: 36, objectFit: "contain" }}
                            onError={(e) => { e.target.style.display = "none"; }}
                        />
                    </div>

                    {/* 404 Number */}
                    <motion.div
                        initial={{ scale: 0.5, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        transition={{ delay: 0.2, type: "spring", stiffness: 200 }}
                        style={{
                            fontSize: "96px",
                            fontWeight: 800,
                            color: "#ff3e43",
                            lineHeight: 1,
                            marginBottom: "8px",
                            letterSpacing: "-4px",
                        }}
                    >
                        404
                    </motion.div>

                    {/* Divider */}
                    <div style={{
                        width: 48,
                        height: 3,
                        background: "#ff3e43",
                        borderRadius: 2,
                        margin: "16px auto 24px",
                    }} />

                    {/* Title */}
                    <h1 style={{
                        fontSize: "24px",
                        fontWeight: 700,
                        color: "#1a1a1a",
                        margin: "0 0 12px",
                    }}>
                        Page not found
                    </h1>

                    {/* Description */}
                    <p style={{
                        fontSize: "14px",
                        color: "#888",
                        lineHeight: 1.6,
                        margin: "0 0 32px",
                        maxWidth: "380px",
                        marginLeft: "auto",
                        marginRight: "auto",
                    }}>
                        The page you're looking for doesn't exist or has been moved.
                        Let's get you back on track.
                    </p>

                    {/* Action buttons */}
                    <div style={{
                        display: "flex",
                        gap: 12,
                        justifyContent: "center",
                        flexWrap: "wrap",
                        marginBottom: "32px",
                    }}>
                        <motion.button
                            whileHover={{ scale: 1.02 }}
                            whileTap={{ scale: 0.98 }}
                            onClick={() => navigate(-1)}
                            style={{
                                padding: "10px 22px",
                                borderRadius: "10px",
                                border: "1.5px solid #e0e0e0",
                                background: "#fff",
                                color: "#444",
                                fontSize: "14px",
                                fontWeight: 500,
                                cursor: "pointer",
                                transition: "all 0.2s",
                            }}
                            onMouseEnter={(e) => {
                                e.currentTarget.style.borderColor = "#ff3e43";
                                e.currentTarget.style.color = "#ff3e43";
                            }}
                            onMouseLeave={(e) => {
                                e.currentTarget.style.borderColor = "#e0e0e0";
                                e.currentTarget.style.color = "#444";
                            }}
                        >
                            ← Go Back
                        </motion.button>

                        <motion.button
                            whileHover={{ scale: 1.02 }}
                            whileTap={{ scale: 0.98 }}
                            onClick={() => navigate("/")}
                            style={{
                                padding: "10px 24px",
                                borderRadius: "10px",
                                border: "none",
                                background: "#ff3e43",
                                color: "#fff",
                                fontSize: "14px",
                                fontWeight: 500,
                                cursor: "pointer",
                                transition: "all 0.2s",
                            }}
                            onMouseEnter={(e) => {
                                e.currentTarget.style.background = "#e0353a";
                            }}
                            onMouseLeave={(e) => {
                                e.currentTarget.style.background = "#ff3e43";
                            }}
                        >
                            Go to Home
                        </motion.button>
                    </div>

                    {/* Quick links */}
                    <div>
                        <p style={{
                            fontSize: "12px",
                            color: "#999",
                            marginBottom: "12px",
                        }}>
                            Quick access:
                        </p>
                        <div style={{
                            display: "flex",
                            gap: "20px",
                            justifyContent: "center",
                            flexWrap: "wrap",
                        }}>
                            {["Dashboard", "Investments", "Companies", "Support"].map((item) => (
                                <a
                                    key={item}
                                    href="#"
                                    onClick={(e) => {
                                        e.preventDefault();
                                        navigate(`/${item.toLowerCase()}`);
                                    }}
                                    style={{
                                        fontSize: "13px",
                                        color: "#666",
                                        textDecoration: "none",
                                        transition: "color 0.2s",
                                        cursor: "pointer",
                                    }}
                                    onMouseEnter={(e) => e.currentTarget.style.color = "#ff3e43"}
                                    onMouseLeave={(e) => e.currentTarget.style.color = "#666"}
                                >
                                    {item}
                                </a>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Footer */}
                <motion.p
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    transition={{ delay: 0.5 }}
                    style={{
                        marginTop: "24px",
                        fontSize: "12px",
                        color: "#bbb",
                        textAlign: "center",
                    }}
                >
                    Need assistance? <a href="#" style={{ color: "#ff3e43", textDecoration: "none", fontWeight: 500 }}>Contact support</a>
                </motion.p>
            </motion.div>
        </div>
    );
}